"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[9290],{5633(e,t,a){a.r(t),a.d(t,{comp:()=>l,data:()=>n});var s=a(641);const o={},l=(0,a(6262).A)(o,[["render",function(e,t){return(0,s.uX)(),(0,s.CE)("div",null,[...t[0]||(t[0]=[(0,s.Fv)('<h1 id="submenu-templates" tabindex="-1"><a class="header-anchor" href="#submenu-templates"><span>Submenu Templates</span></a></h1><p>Each top-level menu item can use a different <strong>submenu style</strong>. This lets you mix simple dropdowns with rich mega menus across the navigation.</p><h2 id="available-styles" tabindex="-1"><a class="header-anchor" href="#available-styles"><span>Available styles</span></a></h2><table><thead><tr><th>Style</th><th>Description</th><th>Best for</th></tr></thead><tbody><tr><td>Two Image Mega Menu</td><td>Link columns with two promo images on the right</td><td>Default jewellery mega menu</td></tr><tr><td>Columns With Promo</td><td>Link columns with one promo area</td><td>Broad categories, such as Jewellery or Collections</td></tr><tr><td>Editorial</td><td>Image-led menu layout</td><td>Brand or lookbook style menus</td></tr><tr><td>Product Showcase</td><td>Product-card style menu</td><td>Featured products or &quot;Shop by&quot; menus</td></tr><tr><td>Compact</td><td>Minimal link dropdown</td><td>Short lists, such as Sale or About</td></tr><tr><td>No Submenu</td><td>Single menu link only</td><td>Flat links</td></tr></tbody></table><p><img src="/hyva-jewelry-theme/screenshots/header-footer-builder-submenu-settings.png" alt="Header, Footer and Mega Menu Builder submenu template settings"></p><h2 id="right-promo-images" tabindex="-1"><a class="header-anchor" href="#right-promo-images"><span>Right promo images</span></a></h2><p>For menu styles that support promo images, configure up to two promo images per top-level item:</p><ul><li><strong>Image 1 label</strong> / <strong>Image 1</strong></li><li><strong>Image 2 label</strong> / <strong>Image 2</strong></li></ul><p>These show as clickable promotional tiles inside the mega menu. Use them for a collection, sale, or seasonal campaign.</p><h2 id="choosing-a-style-per-item" tabindex="-1"><a class="header-anchor" href="#choosing-a-style-per-item"><span>Choosing a style per item</span></a></h2><ol><li>Select the top-level item in the menu tree.</li><li>In the right panel, set <strong>Submenu template</strong>.</li><li>Save Configuration.</li></ol><p>Different items can use different styles, so &quot;Rings&quot; can use a product showcase while &quot;Sale&quot; uses a compact dropdown.</p><p><img src="/hyva-jewelry-theme/screenshots/mega-menu.png" alt="Mega menu with promo rail"></p>',13)])])}]]),n=JSON.parse('{"path":"/hyva-jewelry-theme/chrome/submenu-templates.html","title":"Submenu Templates","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Available styles","slug":"available-styles","link":"#available-styles","children":[]},{"level":2,"title":"Right promo images","slug":"right-promo-images","link":"#right-promo-images","children":[]},{"level":2,"title":"Choosing a style per item","slug":"choosing-a-style-per-item","link":"#choosing-a-style-per-item","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"chrome/submenu-templates.md"}')}}]);